$t = Get-ScheduledTask -TaskName "QuantOS-MegaCollect" -ErrorAction SilentlyContinue; if (-not $t) { Write-Host "MISSING — QuantOS-MegaCollect not found" -ForegroundColor Red } else { $c = @{Ready="Green";Running="Yellow";Disabled="Red"}; Write-Host ("State: " + $t.State) -ForegroundColor ($c[[string]$t.State] -eq $null ? "White" : $c[[string]$t.State]); $r = $t | Get-ScheduledTaskInfo; Write-Host "LastRun: $($r.LastRunTime)  Result: $($r.LastTaskResult)  NextRun: $($r.NextRunTime)" }
